import React, { createContext, useState, useContext, useEffect } from 'react';
import { User, LoginRequest, ApiResponse } from '../types';
import { authService } from '../services/api';
import toast from 'react-hot-toast';

interface AuthContextType {
  user: User | null;
  loading: boolean;
  error: string | null;
  login: (credentials: LoginRequest) => Promise<void>;
  logout: () => void;
  isAuthenticated: boolean;
  verifyToken: () => Promise<boolean>;
  updateUser: (userData: Partial<User>) => Promise<void>;
  clearError: () => void;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const AuthProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<User | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  // Verificar token ao iniciar
  useEffect(() => {
    const checkAuth = async () => {
      try {
        await verifyToken();
      } catch (error) {
        console.error("Erro ao verificar autenticaĂ§ĂŁo:", error);
      } finally {
        setLoading(false);
      }
    };
    
    checkAuth();
  }, []);

  // Limpar mensagens de erro
  const clearError = () => {
    setError(null);
  };

  // FunĂ§ĂŁo para verificar se o token Ă© vĂˇlido
  const verifyToken = async (): Promise<boolean> => {
    const token = localStorage.getItem('token');
    
    if (!token) {
      console.log("[Auth] Nenhum token encontrado");
      setUser(null);
      return false;
    }

    try {
      console.log("[Auth] Verificando token...");
      const response = await authService.verificarToken();
      
      if (response && response.usuario) {
        // Atualizar o usuĂˇrio com os dados da resposta
        const userData: User = {
          id: response.usuario.id,
          email: response.usuario.email,
          papel: response.usuario.papel,
          nome: response.usuario.nome || 'UsuĂˇrio',
          perfil: response.usuario.perfil
        };
        
        console.log("[Auth] UsuĂˇrio autenticado com sucesso:", userData.email);
        
        setUser(userData);
        return true;
      } else {
        console.warn("[Auth] Dados de usuĂˇrio nĂŁo encontrados na resposta");
        throw new Error("Dados de usuĂˇrio nĂŁo encontrados na resposta");
      }
    } catch (error) {
      console.error('[Auth] Erro na verificaĂ§ĂŁo do token:', error);
      // Limpar dados de autenticaĂ§ĂŁo
      localStorage.removeItem('token');
      localStorage.removeItem('papel');
      localStorage.removeItem('email');
      setUser(null);
      return false;
    }
  };

  // FunĂ§ĂŁo de login
  const login = async (credentials: LoginRequest): Promise<void> => {
    setLoading(true);
    setError(null);
    
    try {
      console.log("[Auth] Tentando fazer login com:", credentials.email);
      const response = await authService.login(credentials);
      
      if (!response || !response.token) {
        throw new Error("Token nĂŁo encontrado na resposta");
      }
      
      // Salvar dados no localStorage
      localStorage.setItem('token', response.token);
      
      // Atualizar estado do usuĂˇrio
      const userData: User = {
        id: response.usuario.id,
        email: response.usuario.email,
        papel: response.papel,
        nome: response.usuario.nome,
        perfil: response.usuario.perfil
      };
      
      console.log("[Auth] Login bem-sucedido:", userData.email);
      setUser(userData);
      toast.success("Login realizado com sucesso!");
    } catch (error: any) {
      console.error('[Auth] Erro no login:', error);
      const errorMessage = error.response?.data?.message || error.message || "Erro ao fazer login";
      setError(errorMessage);
      toast.error(errorMessage);
      throw error;
    } finally {
      setLoading(false);
    }
  };

  // FunĂ§ĂŁo de atualizaĂ§ĂŁo do usuĂˇrio
  const updateUser = async (userData: Partial<User>): Promise<void> => {
    setLoading(true);
    setError(null);
    
    try {
      if (!user) {
        throw new Error("UsuĂˇrio nĂŁo autenticado");
      }
      
      // Implementar chamada Ă  API para atualizar o usuĂˇrio
      // Exemplo:
      // const response = await authService.updateUser(userData);
      
      // Por enquanto, vamos apenas atualizar o estado local
      const updatedUser = { ...user, ...userData };
      setUser(updatedUser);
      toast.success("Perfil atualizado com sucesso!");
    } catch (error: any) {
      console.error('[Auth] Erro na atualizaĂ§ĂŁo do usuĂˇrio:', error);
      const errorMessage = error.response?.data?.message || error.message || "Erro ao atualizar usuĂˇrio";
      setError(errorMessage);
      toast.error(errorMessage);
      throw error;
    } finally {
      setLoading(false);
    }
  };

  // FunĂ§ĂŁo de logout
  const logout = () => {
    localStorage.removeItem('token');
    localStorage.removeItem('papel');
    localStorage.removeItem('email');
    setUser(null);
    toast.success("Logout realizado com sucesso!");
  };

  const value = {
    user,
    loading,
    error,
    login,
    logout,
    isAuthenticated: !!user,
    verifyToken,
    updateUser,
    clearError
  };

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
};

// Hook personalizado para usar o contexto
export const useAuth = (): AuthContextType => {
  const context = useContext(AuthContext);
  if (context === undefined) {
    throw new Error('useAuth deve ser usado dentro de um AuthProvider');
  }
  return context;
};
